module binary_counter(
    input                 reset_clk,
    input                 rst,
    input                 enable,

    output reg [3:0]      count
);

// Counter implementation
always @(posedge reset_clk) begin
    if (rst) begin
        count <= 4'd0;
    end
    else if (enable) begin
        count <= count + 1;
    end
end

endmodule
